// Check if current time is in maintenance window
// Maintenance: 21:00-22:30 UTC (06:00-07:30 KST)
const now = new Date();
const utcHour = now.getUTCHours();
const utcMinute = now.getUTCMinutes();
const totalMinutes = utcHour * 60 + utcMinute;

// 21:00 UTC = 1260 minutes, 22:30 UTC = 1350 minutes
const maintenanceStart = 21 * 60; // 1260
const maintenanceEnd = 22 * 60 + 30; // 1350

const isMaintenanceWindow = totalMinutes >= maintenanceStart && totalMinutes < maintenanceEnd;

return [{ json: { isTradingEnabled: !isMaintenanceWindow, currentTimeUTC: now.toISOString() } }];

// 현재 데이터 + 이전 데이터 (트렌드 비교용)
const items = $input.all();
const current = items[0]?.json || {};
const previous = items[1]?.json || {};

// 이전 트렌드 정보 추가
current.previous_trend_1h = previous.trend_1h || current.trend_1h;
current.previous_trend_4h = previous.trend_4h || current.trend_4h;
current.previous_timestamp = previous.timestamp || null;

return [{ json: current }];

