  TEMPLATES[t.template_key] = t.template_content;
});

// Parse configs
const getConfig = (key) => {
  const cfg = systemConfigs.find(c => c.key === key);
  return cfg ? (typeof cfg.value === 'string' ? JSON.parse(cfg.value) : cfg.value) : {};
};

const SL_CONFIG = getConfig('sl_config');
const HOLD_CONFIG = getConfig('hold_config');
const PASSIVITY_CONFIG = getConfig('passivity_config');
const COMPETITION_CONFIG = getConfig('competition_config');
const DOWNTREND_CONFIG = getConfig('downtrend_config');
const ANALYSIS_CONFIG = getConfig('analysis_config');

// ============================================
// 3. LOAD ALL FUNCTIONS FROM CODE_MODULES
// ============================================
const loadedFunctions = {};

codeModules.forEach(module => {
