    try {
      const funcCode = module.module_code;
      const funcMatch = funcCode.match(/function\s+(\w+)/);
      if (funcMatch) {
        const wrappedCode = `return (${funcCode.trim()})`;
        loadedFunctions[module.module_key] = new Function(wrappedCode)();
      }
    } catch (e) {
      console.log(`Failed to load module ${module.module_key}: ${e.message}`);
    }
  }
});

console.log(`Loaded ${Object.keys(loadedFunctions).length} modules from code_modules`);

// ============================================
// 4. CONFIGURATION CONSTANTS
// ============================================
const ROLLING_WINDOW = ANALYSIS_CONFIG.ROLLING_WINDOW || 50;
const MIN_SAMPLE_SIZE = ANALYSIS_CONFIG.MIN_SAMPLE_SIZE || 5;
