  return isNaN(num) ? 'N/A' : num.toFixed(decimals); 
};

function fillTemplate(templateKey, vars = {}) {
  let template = TEMPLATES[templateKey] || '';
  Object.entries(vars).forEach(([key, value]) => {
    template = template.replace(new RegExp(`{{${key}}}`, 'g'), value || '');
  });
  return template;
