function analyzeDecisionReasoning(modelId, recentDecisions, limit = 5) {
  const modelDecisions = recentDecisions
    .filter(d => d.model_id === modelId && d.reasoning)
    .sort((a, b) => new Date(b.created_at || b.timestamp) - new Date(a.created_at || a.timestamp))
    .slice(0, limit);

  if (modelDecisions.length === 0) return null;

  const recentReasonings = modelDecisions.map(d => ({
    action: d.action,
    reasoning: d.reasoning,
    confidence: d.confidence,
    timestamp: d.created_at || d.timestamp
  }));

  const noActionDecisions = modelDecisions.filter(d => 
    d.action === 'NO_ACTION' || d.action === 'HOLD'
  );

  const reasoningKeywords = {};
  const commonPatterns = [
    { pattern: /wait|waiting/i, label: 'WAITING' },
    { pattern: /unclear|uncertain|mixed/i, label: 'UNCERTAIN' },
    { pattern: /no.*signal|weak.*signal|low.*score/i, label: 'WEAK_SIGNAL' },
    { pattern: /rsi.*neutral|rsi.*range/i, label: 'RSI_NEUTRAL' },
    { pattern: /consolidat|rang|sideways/i, label: 'RANGING' },
    { pattern: /risk|protect|safe|conserv/i, label: 'RISK_AVERSE' },
    { pattern: /trend.*unclear|no.*trend/i, label: 'NO_TREND' }
  ];

  noActionDecisions.forEach(d => {
    const reasoning = (d.reasoning || '').toLowerCase();
    commonPatterns.forEach(p => {
      if (p.pattern.test(reasoning)) {
        reasoningKeywords[p.label] = (reasoningKeywords[p.label] || 0) + 1;
      }
    });
  });

  let repetitionWarning = null;
  const repeatedPatterns = Object.entries(reasoningKeywords)
    .filter(([_, count]) => count >= 2)
    .sort((a, b) => b[1] - a[1]);

  if (repeatedPatterns.length > 0 && noActionDecisions.length >= 3) {
    const topPattern = repeatedPatterns[0];
    const patternMessages = {
      'WAITING': 'You keep "waiting" - markets reward action, not patience!',
      'UNCERTAIN': 'Repeated "uncertainty" - perfect clarity never comes. Trade the edge!',
      'WEAK_SIGNAL': 'Multiple "weak signal" excuses - are you being too picky?',
      'RSI_NEUTRAL': 'RSI is neutral most of the time - this should not block trading',
      'RANGING': 'Market is always "ranging" somewhere - find opportunities within it',
      'RISK_AVERSE': 'Excessive risk aversion - remember, NO position = NO gains',
      'NO_TREND': 'Waiting for "clear trend" - trend following is not the only strategy'
    };

    repetitionWarning = {
      pattern: topPattern[0],
      count: topPattern[1],
      message: patternMessages[topPattern[0]] || 'Repeated reasoning pattern detected',
      severity: topPattern[1] >= 4 ? 'CRITICAL' : topPattern[1] >= 3 ? 'HIGH' : 'MEDIUM'
    };
  }

  const lastThreeReasons = recentReasonings.slice(0, 3).map((r, i) => 
    `${i + 1}. [${r.action}] ${r.reasoning.substring(0, 200)}${r.reasoning.length > 200 ? '...' : ''}`
  );

  let reflectionQuestion = null;
  if (noActionDecisions.length >= 3) {
    const lastNoAction = noActionDecisions[0];
    reflectionQuestion = `Your last NO_ACTION reason was: "${lastNoAction.reasoning.substring(0, 150)}..." - Has anything changed since then?`;
  }

  return {
    recentReasonings,
    lastThreeReasons,
    noActionCount: noActionDecisions.length,
    repetitionWarning,
    reflectionQuestion,
    topPatterns: repeatedPatterns.slice(0, 3),
    hasRepetitivePattern: repeatedPatterns.length > 0,
    summary: repetitionWarning 
      ? `⚠️ PATTERN DETECTED: ${repetitionWarning.message}`
      : noActionDecisions.length >= 3 
        ? '📊 Multiple NO_ACTION decisions - review your reasoning'
        : '✅ Decision reasoning looks varied'
  };
}

