// ============================================
// REGIME TRANSITION DETECTION
// ============================================
function classifyMarketState(data) {
  if (!data) return 'UNKNOWN';
  const trend1h = data.trend_1h || 'NEUTRAL';
  const trend4h = data.trend_4h || 'NEUTRAL';
  const trend1d = data.trend_1d || 'NEUTRAL';
  const atr = parseFloat(data.atr) || 0;
  const price = parseFloat(data.close_price) || 0;
  const bbUpper = parseFloat(data.bb_upper) || 0;
  const bbLower = parseFloat(data.bb_lower) || 0;
  const bbWidthPct = price > 0 ? ((bbUpper - bbLower) / price) * 100 : 0;

  const isHighVolatility = bbWidthPct > 0.5 || atr > price * 0.005;
  const trendScore = (trend1h === 'BULLISH' ? 1 : trend1h === 'BEARISH' ? -1 : 0) +
                     (trend4h === 'BULLISH' ? 1 : trend4h === 'BEARISH' ? -1 : 0) +
                     (trend1d === 'BULLISH' ? 1 : trend1d === 'BEARISH' ? -1 : 0);

  if (Math.abs(trendScore) >= 2) {
    return trendScore > 0 ? 'TRENDING_UP' : 'TRENDING_DOWN';
  } else if (isHighVolatility) {
    return 'HIGH_VOLATILITY';
  }
  return 'RANGING';
}

const currentMarket = marketHistory[marketHistory.length - 1];
const previousMarket = marketHistory[marketHistory.length - 2];

const currentRegime = classifyMarketState(currentMarket);
const previousRegime = classifyMarketState(previousMarket);
const regimeChanged = currentRegime !== previousRegime && previousRegime !== 'UNKNOWN';

// Recent regime history (last 10 data points)
const recentRegimes = marketHistory.slice(-10).map(m => classifyMarketState(m));
const regimeStability = recentRegimes.filter(r => r === currentRegime).length / recentRegimes.length;

// ============================================
// MODEL-SPECIFIC REGIME PREFERENCES
// ============================================
function analyzeModelRegimePreference(modelId, trades) {
  const modelTrades = trades.filter(t => t.model_id === modelId && t.entry_market_state);
  if (modelTrades.length < 5) return null;

  const regimeStats = {};
  const regimes = ['TRENDING_UP', 'TRENDING_DOWN', 'RANGING', 'HIGH_VOLATILITY'];

  for (const regime of regimes) {
    const regimeTrades = modelTrades.filter(t => t.entry_market_state === regime);
    if (regimeTrades.length >= 2) {
      const wins = regimeTrades.filter(t => parseFloat(t.realized_pnl || 0) > 0).length;
      const avgPnl = regimeTrades.reduce((sum, t) => sum + parseFloat(t.realized_pnl || 0), 0) / regimeTrades.length;
      regimeStats[regime] = {
        count: regimeTrades.length,
        winRate: ((wins / regimeTrades.length) * 100).toFixed(0),
        avgPnl: avgPnl.toFixed(2),
        isPreferred: wins / regimeTrades.length >= 0.5 && avgPnl > 0
      };
    }
  }

  // Find best regime
  let bestRegime = null;
  let bestWR = 0;
  for (const [regime, stats] of Object.entries(regimeStats)) {
    if (parseFloat(stats.winRate) > bestWR && stats.count >= 3) {
      bestWR = parseFloat(stats.winRate);
      bestRegime = regime;
    }
  }

  return { regimeStats, bestRegime, bestWR };
}

// ============================================
// INDICATOR CORRELATION ANALYSIS
// ============================================
function analyzeIndicatorCorrelation(trades) {
  if (trades.length < 10) return null;

  const correlations = {
    rsi: { zones: {}, optimal: null },
    trend: { bullish: { wins: 0, total: 0 }, bearish: { wins: 0, total: 0 } },
    macd: { positive: { wins: 0, total: 0 }, negative: { wins: 0, total: 0 } }
  };

  for (const t of trades) {
    const win = parseFloat(t.realized_pnl || 0) > 0;
    const rsi = parseFloat(t.entry_rsi);

    // RSI zones
    if (rsi) {
      const zone = rsi < 30 ? '<30' : rsi < 40 ? '30-40' : rsi < 50 ? '40-50' : 
                   rsi < 60 ? '50-60' : rsi < 70 ? '60-70' : '>70';
      if (!correlations.rsi.zones[zone]) correlations.rsi.zones[zone] = { wins: 0, total: 0 };
      correlations.rsi.zones[zone].total++;
      if (win) correlations.rsi.zones[zone].wins++;
    }

    // Trend correlation
    const trend = t.entry_trend || t.trend_at_decision;
    if (trend === 'BULLISH') {
      correlations.trend.bullish.total++;
      if (win) correlations.trend.bullish.wins++;
    } else if (trend === 'BEARISH') {
      correlations.trend.bearish.total++;
      if (win) correlations.trend.bearish.wins++;
    }
  }

  // Find optimal RSI zone
  let optimalZone = null;
  let optimalWR = 0;
  for (const [zone, stats] of Object.entries(correlations.rsi.zones)) {
    if (stats.total >= 3) {
      const wr = stats.wins / stats.total;
      if (wr > optimalWR) {
        optimalWR = wr;
        optimalZone = zone;
      }
    }
  }
  correlations.rsi.optimal = optimalZone ? { zone: optimalZone, winRate: (optimalWR * 100).toFixed(0) } : null;

  return correlations;
}

// ============================================
// BUILD ANALYSIS OUTPUT
// ============================================
const modelAnalysis = {};
for (const p of portfolios) {
  const modelId = p.model_id;
  modelAnalysis[modelId] = {
    regimePreference: analyzeModelRegimePreference(modelId, recentTrades),
    indicatorCorrelation: analyzeIndicatorCorrelation(recentTrades.filter(t => t.model_id === modelId))
  };
}

const globalCorrelation = analyzeIndicatorCorrelation(recentTrades);

// ============================================
