  'OPEN_LONG': 'OPEN_LONG',
  'OPEN_SHORT': 'OPEN_SHORT',
  'CLOSE_LONG': 'CLOSE_LONG',
  'CLOSE_SHORT': 'CLOSE_SHORT',
  'NO_ACTION': 'NO_ACTION',
