const previousTrend = previous.trend_1h || currentTrend;

function detectTrendReversal(prevTrend, currTrend) {
  if (prevTrend === currTrend) return null;

  if (prevTrend === 'BULLISH' && currTrend === 'BEARISH') {
    return { type: 'REVERSAL', severity: 'CRITICAL', templateKey: 'trend_reversal_bull_to_bear', affectedPositions: 'LONG' };
  }
  if (prevTrend === 'BEARISH' && currTrend === 'BULLISH') {
    return { type: 'REVERSAL', severity: 'CRITICAL', templateKey: 'trend_reversal_bear_to_bull', affectedPositions: 'SHORT' };
  }

  if (prevTrend === 'BULLISH' && currTrend === 'NEUTRAL') {
    return { type: 'WEAKENING', severity: 'WARNING', templateKey: 'trend_weakening_bull', affectedPositions: 'LONG' };
  }
  if (prevTrend === 'BEARISH' && currTrend === 'NEUTRAL') {
    return { type: 'WEAKENING', severity: 'WARNING', templateKey: 'trend_weakening_bear', affectedPositions: 'SHORT' };
  }

  if (prevTrend === 'NEUTRAL' && currTrend === 'BULLISH') {
    return { type: 'ESTABLISHED', severity: 'INFO', templateKey: 'trend_established_bull', affectedPositions: 'SHORT' };
  }
  if (prevTrend === 'NEUTRAL' && currTrend === 'BEARISH') {
    return { type: 'ESTABLISHED', severity: 'INFO', templateKey: 'trend_established_bear', affectedPositions: 'LONG' };
  }

  return null;
}

const trendReversal = detectTrendReversal(previousTrend, currentTrend);


