function analyzeDecisionHistory(modelId, decisions, portfolioRank, totalModels) {
  const modelDecisions = decisions
    .filter(d => d.model_id === modelId)
    .sort((a, b) => new Date(b.created_at || b.timestamp) - new Date(a.created_at || a.timestamp))
    .slice(0, 10);

  if (modelDecisions.length === 0) {
    return { consecutiveNoAction: 0, passivityLevel: 'UNKNOWN', shouldForceAction: false };
  }

  let consecutiveNoAction = 0;
  for (const d of modelDecisions) {
    if (d.action === 'NO_ACTION' || d.action === 'HOLD') {
      consecutiveNoAction++;
    } else {
      break;
    }
  }

  const noActionCount = modelDecisions.filter(d => d.action === 'NO_ACTION' || d.action === 'HOLD').length;
  const noActionRate = (noActionCount / modelDecisions.length) * 100;

  let passivityLevel = 'NORMAL';
  let shouldForceAction = false;
  let warningMessage = '';

  const thresholds = PASSIVITY_CONFIG.thresholds || { warning: 3, critical: 5, extreme: 7 };
  const bottomHalf = portfolioRank > Math.ceil(totalModels / 2);

  if (consecutiveNoAction >= thresholds.extreme) {
    passivityLevel = 'EXTREME';
    shouldForceAction = true;
    warningMessage = `🚨 CRITICAL: ${consecutiveNoAction} consecutive NO_ACTION! You MUST trade now or face elimination!`;
  } else if (consecutiveNoAction >= thresholds.critical) {
    passivityLevel = 'CRITICAL';
    shouldForceAction = bottomHalf;
    warningMessage = `⚠️ WARNING: ${consecutiveNoAction} consecutive NO_ACTION! ${bottomHalf ? 'Bottom tier - action required!' : 'Consider trading'}`;
  } else if (consecutiveNoAction >= thresholds.warning) {
    passivityLevel = 'WARNING';
    warningMessage = `📊 NOTICE: ${consecutiveNoAction} consecutive NO_ACTION. Active trading recommended.`;
  }

  return {
    consecutiveNoAction,
    noActionRate: noActionRate.toFixed(0),
    passivityLevel,
    shouldForceAction,
    warningMessage,
    recentDecisions: modelDecisions.length
  };
}

function analyzePositionSlots(modelPositions, maxPositions = 4, rank, totalModels) {
  const openPositions = modelPositions.filter(p => p.status === 'OPEN' || !p.status);
  const usedSlots = openPositions.length;
  const availableSlots = maxPositions - usedSlots;
  const canOpenNew = availableSlots > 0;

  const bottomHalf = rank > Math.ceil(totalModels / 2);

  let message = '';
  if (usedSlots === 0) {
    message = bottomHalf 
      ? `🔴 NO POSITIONS! ${maxPositions} slots FREE. Bottom tier = MUST open positions!`
      : `📊 No positions. ${maxPositions} slots available.`;
  } else if (availableSlots === 0) {
    message = `📊 Full capacity: ${usedSlots}/${maxPositions} positions. Consider closing weak ones.`;
  } else {
    message = bottomHalf
      ? `⚠️ Only ${usedSlots}/${maxPositions} slots used! ${availableSlots} FREE slots - USE THEM!`
      : `📊 ${usedSlots}/${maxPositions} positions. ${availableSlots} slots available.`;
  }

  return {
    usedSlots,
    availableSlots,
    maxPositions,
    canOpenNew,
    utilizationPct: ((usedSlots / maxPositions) * 100).toFixed(0),
    message,
    positions: openPositions.map(p => ({
      side: p.side,
      entry: p.entry_price,
      pnl: p.unrealized_pnl
    }))
  };
}

function classifyMarketState(market) {
  const rsi = parseFloat(market.rsi) || 50;
  const trend = market.trend_1h || 'NEUTRAL';
  const atrVal = parseFloat(market.atr) || 0;
  const price = parseFloat(market.close_price) || 90000;
  const atrPct = (atrVal / price) * 100;

  let state = 'NEUTRAL';
  let confidence = 50;

  if (trend === 'BULLISH' && rsi > 50 && rsi < 70) {
    state = 'BULLISH_MOMENTUM';
    confidence = Math.min(80, 50 + (rsi - 50));
  } else if (trend === 'BEARISH' && rsi < 50 && rsi > 30) {
    state = 'BEARISH_MOMENTUM';
    confidence = Math.min(80, 50 + (50 - rsi));
  } else if (rsi > 70) {
    state = 'OVERBOUGHT';
    confidence = Math.min(90, rsi);
  } else if (rsi < 30) {
    state = 'OVERSOLD';
    confidence = Math.min(90, 100 - rsi);
  } else if (atrPct > 1.5) {
    state = 'HIGH_VOLATILITY';
    confidence = 60;
  } else if (atrPct < 0.3) {
    state = 'LOW_VOLATILITY';
    confidence = 60;
  }

  return { state, confidence, rsi, trend, atrPct: atrPct.toFixed(2) };
}

function analyzeDowntrendStrength(marketHistory) {
  if (marketHistory.length < 5) return { strength: 'UNKNOWN', score: 0 };

  const recent = marketHistory.slice(-20);
  const prices = recent.map(m => parseFloat(m.close_price) || 0);

  let downMoves = 0;
  let totalMove = 0;
  for (let i = 1; i < prices.length; i++) {
    const move = prices[i] - prices[i-1];
    totalMove += move;
    if (move < 0) downMoves++;
  }

  const downRatio = downMoves / (prices.length - 1);
  const avgMove = totalMove / (prices.length - 1);

  let strength = 'WEAK';
  let score = 0;

  if (downRatio > 0.7 && avgMove < -50) {
    strength = 'STRONG'; score = 8;
  } else if (downRatio > 0.6 && avgMove < -30) {
    strength = 'MODERATE'; score = 6;
  } else if (downRatio > 0.5) {
    strength = 'WEAK'; score = 4;
  } else {
    strength = 'NONE'; score = 0;
  }

  return { strength, score, downRatio: (downRatio * 100).toFixed(0), avgMove: avgMove.toFixed(0) };
}

function analyzeUptrendStrength(marketHistory) {
  if (marketHistory.length < 5) return { strength: 'UNKNOWN', score: 0 };

  const recent = marketHistory.slice(-20);
  const prices = recent.map(m => parseFloat(m.close_price) || 0);

  let upMoves = 0;
  let totalMove = 0;
  for (let i = 1; i < prices.length; i++) {
    const move = prices[i] - prices[i-1];
    totalMove += move;
    if (move > 0) upMoves++;
  }

  const upRatio = upMoves / (prices.length - 1);
  const avgMove = totalMove / (prices.length - 1);

  let strength = 'WEAK';
  let score = 0;

  if (upRatio > 0.7 && avgMove > 50) {
    strength = 'STRONG'; score = 8;
  } else if (upRatio > 0.6 && avgMove > 30) {
    strength = 'MODERATE'; score = 6;
  } else if (upRatio > 0.5) {
    strength = 'WEAK'; score = 4;
  } else {
    strength = 'NONE'; score = 0;
  }

  return { strength, score, upRatio: (upRatio * 100).toFixed(0), avgMove: avgMove.toFixed(0) };
}

function analyzeShortOpportunity(market, downtrendAnalysis) {
  let score = 0;
  const factors = [];

  const rsi = parseFloat(market.rsi) || 50;
  if (rsi > 70) { score += 3; factors.push('RSI overbought'); }
  else if (rsi > 60) { score += 1; factors.push('RSI elevated'); }

  if (market.trend_1h === 'BEARISH') { score += 2; factors.push('Bearish trend'); }

  if (downtrendAnalysis.strength === 'STRONG') { score += 3; factors.push('Strong downtrend'); }
  else if (downtrendAnalysis.strength === 'MODERATE') { score += 2; factors.push('Moderate downtrend'); }

  return { score, factors, recommendation: score >= 6 ? 'FAVORABLE' : score >= 4 ? 'NEUTRAL' : 'UNFAVORABLE' };
}

function analyzeLongOpportunity(market, uptrendAnalysis) {
  let score = 0;
  const factors = [];

  const rsi = parseFloat(market.rsi) || 50;
  if (rsi < 30) { score += 3; factors.push('RSI oversold'); }
  else if (rsi < 40) { score += 1; factors.push('RSI depressed'); }

  if (market.trend_1h === 'BULLISH') { score += 2; factors.push('Bullish trend'); }

  if (uptrendAnalysis.strength === 'STRONG') { score += 3; factors.push('Strong uptrend'); }
  else if (uptrendAnalysis.strength === 'MODERATE') { score += 2; factors.push('Moderate uptrend'); }

  return { score, factors, recommendation: score >= 6 ? 'FAVORABLE' : score >= 4 ? 'NEUTRAL' : 'UNFAVORABLE' };
}

function generatePsychologyPressure(rank, totalModels, decisionHistory, overtakeInfo) {
  const isChampion = rank === 1;
  const isTopTier = rank <= Math.ceil(totalModels * 0.3);
  const isBottomHalf = rank > Math.ceil(totalModels / 2);
  const isLastPlace = rank === totalModels;

  let pressure = '';
  let pressureType = 'NORMAL';
  let requiresAggression = false;

  if (isChampion) {
    pressureType = 'CHAMPION';
    pressure = `👑 **CHAMPION STATUS** - You control REAL MONEY trades!\n💰 Protect your lead. Others are hunting your position.\n⚠️ One bad decision = losing championship privileges!`;
  } else if (isTopTier) {
    pressureType = 'CONTENDER';
    pressure = `🥈 **CONTENDER** - Close to championship!\n${overtakeInfo}\n🎯 One strong trade could make YOU the champion!`;
  } else if (isLastPlace) {
    pressureType = 'ELIMINATION';
    requiresAggression = true;
    pressure = `🚨 **LAST PLACE - ELIMINATION RISK!**\n❌ You are at the BOTTOM. NO_ACTION = certain elimination!\n⚡ MUST trade aggressively NOW!\n${decisionHistory.warningMessage || ''}`;
  } else if (isBottomHalf) {
    pressureType = 'LAGGING';
    requiresAggression = decisionHistory.passivityLevel !== 'NORMAL';
    pressure = `⚠️ **BOTTOM HALF** - Rank #${rank}/${totalModels}\n${overtakeInfo}\n📊 Passive trading won't save you. Trade to climb!\n${decisionHistory.warningMessage || ''}`;
  } else {
    pressureType = 'MID_PACK';
    pressure = `📊 **MID-PACK** - Rank #${rank}/${totalModels}\n${overtakeInfo}\n🎯 Opportunity to break into top tier!`;
  }

  return { pressure, pressureType, requiresAggression };
}

