          confidence: decision.confidence || 0, reasoning: (decision.reasoning || '').substring(0, 500),
          entry_price: decision.entry_price || null, stop_loss: decision.stop_loss || null, take_profit: decision.take_profit || null,
          position_size: decision.position_size || 0, leverage: decision.leverage || 5,
          rank_at_decision: rank, pressure_type: rank ? getPressureType(rank, totalModels) : null,
          market_state: promptData?.market_state || null, rsi_at_decision: promptData?.rsi_at_decision || null, trend_at_decision: promptData?.trend_at_decision || null,
          validation_warnings: validation.warnings, has_validation_warnings: validation.has_warnings, warning_count: validation.warning_count, highest_warning_severity: validation.highest_severity,
          original_action: decision.action, opportunity_score: promptData?.opportunity_score || null, opportunity_direction: promptData?.opportunity_direction || null,
          long_opportunity_score: promptData?.long_opportunity_score || null, short_opportunity_score: promptData?.short_opportunity_score || null,
          downtrend_strength: promptData?.downtrend_strength || null, uptrend_strength: promptData?.uptrend_strength || null,
          consecutive_no_action: promptData?.consecutive_no_action || 0, passivity_level: promptData?.passivity_level || 'UNKNOWN',
          should_force_action: promptData?.should_force_action || false, force_action_reason: promptData?.force_action_reason || null,
          position_slots_available: promptData?.position_slots_available || null, position_slots_used: promptData?.position_slots_used || null,
          entry_trigger: decision.entry_trigger || null
        });
      }
    }
  } catch(e) { console.log(`Error: ${nodeName} - ${e.message}`); }
}

const allDecisions = Array.from(decisionsMap.values());
if (allDecisions.length === 0) return [];
console.log(`v2.5: Processed ${allDecisions.length} decisions (8 models including Cohere)`);
