const decisions = $input.all().map(i => i.json);
const prompts = $('Prepare Competition Prompts').all().map(i => i.json);

// 크레딧/결제 에러 패턴
const creditErrorPatterns = [
  'insufficient_quota', 'billing', 'credit', 'quota',
  'rate_limit', 'too_many_requests', '429', '402',
  'exceeded', 'limit reached', 'payment', 'subscription',
  'budget', 'overloaded', 'capacity'
];

const errors = [];
const creditErrors = [];
const workingModels = [];

for (const d of decisions) {
  const prompt = prompts.find(p => p.model_id === d.model_id);
  const modelName = prompt ? prompt.model_name : 'Unknown';
  const provider = prompt ? prompt.provider : 'unknown';
  const reasoning = (d.reasoning || '').toLowerCase();

  // 에러 판정
  const isError = d.confidence === 0 && (reasoning.includes('error') || reasoning.includes('parse'));

  if (isError) {
    // 크레딧 에러 체크
    const isCreditError = creditErrorPatterns.some(p => reasoning.includes(p));

    const errorInfo = {
      modelName,
      modelId: d.model_id,
      reason: d.reasoning || 'Unknown error',
      provider,
      isCreditError,
      errorType: isCreditError ? 'CREDIT' : 
                 reasoning.includes('timeout') ? 'TIMEOUT' : 
                 reasoning.includes('network') ? 'NETWORK' : 'API'
    };

    errors.push(errorInfo);
    if (isCreditError) creditErrors.push(errorInfo);
  } else {
    workingModels.push({ modelName, modelId: d.model_id, action: d.action, confidence: d.confidence });
  }
}

// 다수 실패 경고 (4개 이상 실패 시)
const isCriticalFailure = errors.length >= 4;
const hasCreditIssue = creditErrors.length > 0;

