let transitionAlert = null;
if (regimeChanged) {
  transitionAlert = {
    from: previousRegime,
    to: currentRegime,
    stability: (regimeStability * 100).toFixed(0) + '%',
    recommendation: regimeStability < 0.5 ? 'WAIT_FOR_CONFIRMATION' : 'ADAPT_STRATEGY'
  };
}

return [{
