// ============================================
// Parse Mistral v2.4 - FIXED Action Normalization
// ============================================

const input = $input.all();

// v2.4: 유효 액션 그대로 유지
const ACTION_ALIASES = {
  'OPEN_LONG': 'OPEN_LONG',
  'OPEN_SHORT': 'OPEN_SHORT',
  'CLOSE_LONG': 'CLOSE_LONG',
  'CLOSE_SHORT': 'CLOSE_SHORT',
  'NO_ACTION': 'NO_ACTION',
  'LONG': 'OPEN_LONG',
  'SHORT': 'OPEN_SHORT',
  'CLOSE': 'CLOSE_LONG',
  'HOLD': 'NO_ACTION',
  'HOLD_POSITION': 'NO_ACTION',
  'HOLD_FOR_TARGET': 'NO_ACTION',
  'WAIT': 'NO_ACTION',
  'MAINTAIN': 'NO_ACTION',
  'KEEP': 'NO_ACTION'
};

function normalizeAction(action) {
  if (!action) return 'NO_ACTION';
  const upper = action.toString().toUpperCase().trim();
  return ACTION_ALIASES[upper] || 'NO_ACTION';
}

function extractJSON(content) {
  const codeBlockMatch = content.match(/```(?:json)?\s*(\{[\s\S]*?\})\s*```/);
  if (codeBlockMatch) {
    return JSON.parse(codeBlockMatch[1]);
  }
  const jsonMatch = content.match(/\{[^{}]*(?:\{[^{}]*\}[^{}]*)*\}/);
  if (jsonMatch) {
    return JSON.parse(jsonMatch[0]);
  }
  throw new Error('No valid JSON found');
}

try {
  const item = input[0];
  if (!item) throw new Error('No input received');

  const response = item.json;
  let content = '';

  if (response.choices && response.choices[0]) {
    content = response.choices[0].message?.content || '';
  }

  let parsed = {};
  try {
    parsed = extractJSON(content);
  } catch (jsonError) {
    const actionMatch = content.match(/"action"\s*:\s*"([^"]+)"/);
    if (actionMatch) {
      parsed.action = actionMatch[1];
    }
  }

