// ============================================
// Parse MiMo-V2 v2.4 - FIXED Action Normalization
// ============================================

// v2.4: 유효 액션 그대로 유지
const ACTION_ALIASES = {
  'OPEN_LONG': 'OPEN_LONG',
  'OPEN_SHORT': 'OPEN_SHORT',
  'CLOSE_LONG': 'CLOSE_LONG',
  'CLOSE_SHORT': 'CLOSE_SHORT',
  'NO_ACTION': 'NO_ACTION',
  'LONG': 'OPEN_LONG',
  'SHORT': 'OPEN_SHORT',
  'CLOSE': 'CLOSE_LONG',
  'HOLD': 'NO_ACTION',
  'HOLD_POSITION': 'NO_ACTION',
  'HOLD_FOR_TARGET': 'NO_ACTION',
  'WAIT': 'NO_ACTION',
  'MAINTAIN': 'NO_ACTION',
  'KEEP': 'NO_ACTION',
  'STAY': 'NO_ACTION'
};

function normalizeAction(action) {
  if (!action) return 'NO_ACTION';
  const upper = action.toString().toUpperCase().trim();
  return ACTION_ALIASES[upper] || 'NO_ACTION';
}

const inputData = $input.item.json;

const prepareData = $('Prepare Competition Prompts').all();
const mimoPrompt = prepareData.find(item => 
  item.json.model_name === 'MiMo-V2'
);
const mimoModelId = mimoPrompt?.json.model_id || 'c7567aec-23ba-4342-a2c1-69855dd2eff6';

let apiContent = '';
try {
  apiContent = inputData.choices?.[0]?.message?.content || inputData.content || '';
} catch (e) {
  apiContent = '';
}

let parsed = {};
try {
  parsed = JSON.parse(apiContent);
} catch (e1) {
  try {
    const cleaned = apiContent.replace(/```json\n?/gi, '').replace(/```/g, '').trim();
    parsed = JSON.parse(cleaned);
  } catch (e2) {
    const match = apiContent.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        parsed = JSON.parse(match[0]);
      } catch (e3) {
        parsed = { action: 'NO_ACTION', confidence: 0, reasoning: 'Parse failed' };
      }
    } else {
      parsed = { action: 'NO_ACTION', confidence: 0, reasoning: 'No JSON found' };
    }
  }
}

const originalAction = parsed.action || 'NO_ACTION';
const normalizedAction = normalizeAction(originalAction);

return {
  json: {
    model_id: mimoModelId,
    symbol: 'BTCUSD',
    action: normalizedAction,
    confidence: parseFloat(parsed.confidence || 0),
    reasoning: (parsed.reasoning || '').substring(0, 500),
    entry_price: parsed.entry_price || null,
    stop_loss: parsed.stop_loss || null,
    take_profit: parsed.take_profit || null,
    position_size: parsed.position_size || 0.02,
    leverage: parseInt(parsed.leverage || 5),
    original_action: originalAction
  }
};

// v10.10: Merge All Data + Recent Decisions for Passivity Tracking
const allInputs = $input.all();

let tradesData = null;
let learningData = null;
let decisionsData = [];

for (const item of allInputs) {
  const json = item.json;

  if (json.model_id && json.action && json.created_at) {
    decisionsData.push(json);
  }
  else if (json.marketData || json.portfolios) {
    tradesData = json;
  }
  else if (json.learningPatterns !== undefined) {
    learningData = json;
  }
}

// Fallback with try-catch for unexecuted nodes
if (!tradesData) {
  try {
    tradesData = $('Limit After Trades').first()?.json || {};
  } catch (e) {
    tradesData = {};
  }
}

if (!learningData) {
  try {
    learningData = $('Analyze Learning Patterns').first()?.json || {};
  } catch (e) {
    learningData = { learningPatterns: null };
    console.log('Analyze Learning Patterns not executed - using default');
  }
}

if (decisionsData.length === 0) {
  try {
    const decisionItems = $('Get Recent Decisions').all();
    decisionsData = decisionItems.map(d => d.json);
  } catch (e) {
    decisionsData = [];
  }
}

const output = {
  marketData: tradesData.marketData || tradesData,
  portfolios: tradesData.portfolios || [],
  models: tradesData.models || [],
  positions: tradesData.positions || [],
  recentTrades: tradesData.recentTrades || [],
  learningPatterns: learningData.learningPatterns || null,
  recentDecisions: decisionsData
};

console.log(`v10.10 Passivity Tracking: ${decisionsData.length} recent decisions loaded`);
return [{ json: output }];

// Consolidate all template data into single item to prevent multiplication
const allItems = $input.all();

// Get first item's data as base (contains market, portfolios, models, etc.)
const baseData = allItems[0]?.json || {};

// Extract all templates into array
const templates = allItems.map(item => item.json);

return [{
