    ...baseData,
    promptTemplates: templates,
    templateCount: templates.length
  }
}];

// Consolidate all config data into single item to prevent multiplication
const allItems = $input.all();

// Get first item's data as base
const baseData = allItems[0]?.json || {};

// Extract all configs into array
const configs = allItems.map(item => item.json);

// Convert to key-value map for easier access
const configMap = {};
configs.forEach(c => {
  if (c.key) configMap[c.key] = c.value;
});

return [{
  json: {
    ...baseData,
    systemConfig: configMap,
    configCount: configs.length
  }
}];

// Consolidate all code modules into single item
